// No deals to sync
return [{
  json: {
    success: true,
    message: 'No deals to sync',
    deals_synced: 0
  }
}];

const response = $input.item.json;
const dealData = $('Get Deals to Sync').item.json;

// FIX #4: Handle direct response (not embedded in array)
const deal = response.data ? JSON.parse(response.data) : response;

// FIX #2: Use closest_task_at directly from lead object
// According to Kommo API documentation:
// https://developers.kommo.com/reference/leads-list
// closest_task_at is a direct field on the lead object

// Extract lead ID
const leadId = deal.id || dealData.kommo_lead_id;

// Extract contact info
const contactId = deal._embedded?.contacts?.[0]?.id || dealData.kommo_contact_id;

// Extract pipeline and status info
// Note: pipeline_name and status_name are NOT in lead response
// They must be fetched from /api/v4/leads/pipelines/{pipeline_id}
// For now, we keep the cached values from previous sync
const pipelineId = deal.pipeline_id || dealData.kommo_pipeline_id;
const statusId = deal.status_id || dealData.kommo_status_id;

// FIX #2: closest_task_at is a direct field on lead object
// Type: int (Unix Timestamp) or null
// Description: The time and date of the closest open task
const closestTaskAtTimestamp = deal.closest_task_at;
const closestTaskAt = closestTaskAtTimestamp 
  ? new Date(closestTaskAtTimestamp * 1000).toISOString() 
  : null;

// FIX #2: has_active_task derived from closest_task_at
// If closest_task_at is not null, there's at least one open task
const hasActiveTask = closestTaskAtTimestamp !== null && closestTaskAtTimestamp > 0;

// Extract responsible user
const responsibleUserId = deal.responsible_user_id || dealData.kommo_responsible_user_id;

// Extract closed_at
// Type: int (Unix Timestamp) or null
const closedAtTimestamp = deal.closed_at;
const closedAt = closedAtTimestamp 
  ? new Date(closedAtTimestamp * 1000).toISOString() 
  : null;

return [{
  json: {
    crm_sync_id: dealData.crm_sync_id,
    lead_id: dealData.lead_id,
    kommo_lead_id: leadId,
    public_number: dealData.public_number,

    // Keep existing values (not returned by lead API)
    kommo_contact_id: contactId ? contactId.toString() : dealData.kommo_contact_id,
    kommo_pipeline_id: pipelineId,
    kommo_pipeline_name: dealData.kommo_pipeline_name, // Cached
    kommo_status_id: statusId,
    kommo_status_name: dealData.kommo_status_name, // Cached
    kommo_responsible_user_id: responsibleUserId || dealData.kommo_responsible_user_id,

    // FIX #2: Use closest_task_at from lead object
    crm_has_active_task: hasActiveTask,
    crm_closest_task_at: closestTaskAt,
    crm_closed_at: closedAt,
    crm_synced_at: new Date().toISOString(),

    // Preserve initial_task_created
    initial_task_created: dealData.initial_task_created,

    // Raw snapshot for debug
    crm_raw_snapshot: JSON.stringify(deal)
  }
}];

const updateResult = $input.item.json;
const dealData = $('Get Deals to Sync').item.json;

return [{
  json: {
    success: true,
    lead_id: updateResult.lead_id,
    kommo_lead_id: updateResult.kommo_lead_id,
    public_number: dealData.public_number,
    crm_synced_at: updateResult.crm_synced_at,
    status_updated: true
  }
}];

const error = $input.item.json;
const dealData = $('Get Deals to Sync').item.json;

return [{
  json: {
    lead_id: dealData.lead_id,
    crm_sync_id: dealData.crm_sync_id,
    kommo_lead_id: dealData.kommo_lead_id,
    error: error.error || error.message || JSON.stringify(error)
  }
}];

// Aggregate results
const allResults = $input.all();

const successful = allResults.filter(r => r.json.success).length;
const failed = allResults.filter(r => !r.json.success).length;

return [{
  json: {
    success: true,
    message: 'CRM Status Sync completed',
    deals_synced: successful,
    deals_failed: failed,
    total: allResults.length,
    synced_at: new Date().toISOString()
  }
}];

const item = $input.item.json;

return [{
  json: {
    ...item,
    kommo_fetch_url: `${$env.KOMMO_BASE_URL}/api/v4/leads/${item.kommo_lead_id}`,
    kommo_auth_header: `Bearer ${$env.KOMMO_ACCESS_TOKEN}`,
  }
}];

const item = $input.item.json;
const dealReq = $('Prepare Fetch Kommo Deal Request').item.json;

const baseUrl = dealReq.kommo_fetch_url.split('/api/v4/')[0];

return [{
  json: {
    ...item,
    kommo_status_url: `${baseUrl}/api/v4/leads/pipelines/${item.kommo_pipeline_id}/statuses/${item.kommo_status_id}`,
    kommo_auth_header: dealReq.kommo_auth_header,
  }
}];

const parsed = $('Prepare Fetch Kommo Status Request').item.json;
const input = $input.item.json;

const status = input.data ? JSON.parse(input.data) : input;

return [{
  json: {
    ...parsed,
    kommo_status_name: status.name || parsed.kommo_status_name
  }
}];
